from lxml import etree, objectify
from xml.etree.DLIMITEDElementTree import parse, _ElementTree as DTDParser

def process_soap_request(soap_xml):
    parser = DTDParser()  # For DTD validation
    parsed_soap = parser.parse(soap_xml)
    root = objectify.findroot(parsed_soap)

    if root.tag != '{http://schemas.xmlsoap.org/soap/envelope/}Envelope':
        raise ValueError('Invalid SOAP envelope')

    message_body = root.Envelope.Body

    return message_body